    c = [0] * (nmax + 1)
    t = [0] * (nmax + 1)
    t[0] = 1
    for k in range(K + 1):
        s = -1 if (k & 1) else 1
        for j in range(nmax + 1):
            c[j] += s * t[j]
        m1 = k + 2
        if m1 <= nmax:
            for j in range(m1, nmax + 1):
                t[j] += t[j - m1]
        m2 = 2 * (k + 1)
        if m2 <= nmax:
            for j in range(m2, nmax + 1):
                t[j] += t[j - m2]
    return c
